export interface RetryableError extends Error {
  retryPromise?: Promise<unknown>;
}

/**
 * Executes the given function and retries it once if the thrown error
 * contains a `retryPromise` property.
 *
 * If `p` throws an error with `retryPromise`, this function waits for
 * that promise to resolve (via @acepad/splashscreen's wrap) and then
 * invokes `p` again.
 *
 * @param p A function returning a value or Promise.
 * @returns The return value of `p`.
 * @throws Rethrows the original error if no retryPromise is present.
 */
export declare function retry<T>(p: () => T | Promise<T>): Promise<T>;
